frappe.ui.form.on("Quotation", {
    before_workflow_action(frm) {

        frm._last_workflow_action = frm.selected_workflow_action;
        console.log("Before Workflow Action:", frm._last_workflow_action);

            const total = frm.doc.base_grand_total || 0;

            if (total <= 0) {
                frappe.msgprint("Amount Must Be Greater Than 0");
                frappe.validated = false;
                return false;
            }

            const roles = frappe.user_roles;
            console.log("Roles:", roles);

            let approvalLimit = 0;
            const topRoles = [
                "Sales Master Manager - ALVOIP",
                "Sales Master Manager - DMS",
                "Sales Master Manager - AVTECH",
                "Sales Manager - ALVOIP",
                "Sales Manager - DMS",
                "Sales Manager - AVTECH",
                "Product Manager - DMS",
                "Product Manager - ALVOIP",
                "Product Manager - AVTECH",
                "System Manager"
            ]; 

            const seniorRoles = [
                    "Senior Sales - ALVOIP",
                    "Senior Sales - DMS",
                    "Senior Sales - AVTECH",
            ]

            const juniorRoles = [
                "Junior Sales - ALVOIP",
                "Junior Sales - DMS",
                "Junior Sales - AVTECH",
            ] 

            const coordinatorRole = [
                "Sales Coordinator - DMS",
                "Sales Coordinator - AVTECH",
                "Sales Coordinator - ALVOIP"
            ]


           const hasAnyRole = (requiredRoles) => {
                return requiredRoles.some(role => roles.includes(role));
            };

            if (hasAnyRole(topRoles)) {
                    console.log("Sales Manager - No limit");
                    return true;

            }
            // =============== Senior Sales - Network DEPT ==============================
            else if (hasAnyRole(seniorRoles)) {
                    approvalLimit = 150000;
                    console.log("Senior - Limit: 150,000 SR");

            } 
              // ===== Junior Sales - Network DEPT =====
            else if (hasAnyRole(juniorRoles)) {
                approvalLimit = 75000;
                console.log("Junior - Limit: 75,000 SR");

            }
            // ===== Sales Coordinator =====
            else if (hasAnyRole(coordinatorRole)) {
                    approvalLimit = 75000; 
            }

            else {

                return;
            }

            if (total > approvalLimit) {
                frappe.msgprint({
                    title: "Approval Alert",
                    message: `This quotation with a value of <b>${total.toLocaleString()} SR</b> exceeds your approval limit (${approvalLimit.toLocaleString()} SR).<br><br>It will be forwarded to the Sales Manager for approval.`,
                    indicator: "blue"
                });

                frm.set_value("workflow_state", "Pending Approval");

            } else {
               return

            }


    }
});

frappe.ui.form.on("Quotation", {
    after_workflow_action(frm) {
    if (frm.doc.workflow_state === "Pending Approval") {
        const roles = frappe.user_roles;

        const juniorRoles = [
            "Junior Sales - ALVOIP",
            "Junior Sales - DMS",
            "Junior Sales - AVTECH"
        ];

        const seniorRoles = [
            "Senior Sales - ALVOIP",
            "Senior Sales - DMS",
            "Senior Sales - AVTECH"
        ];

        const hasAnyRole = (roleList) => {
            return roleList.some(role => roles.includes(role));
        };

        if (hasAnyRole(juniorRoles) || hasAnyRole(seniorRoles)) {
            frappe.call({
                method: "frappe.desk.form.utils.add_comment",
                args: {
                    reference_doctype: frm.doctype,
                    reference_name: frm.doc.name,
                    content: "The quotation requires Sales Manager approval.",
                    comment_email: frappe.session.user,
                    comment_by: frappe.session.user_fullname
                }
            });
        }
    }
},
    onload(frm){
      if (frm.doc.workflow_state === "Pending Approval") {
            const roles = frappe.user_roles;
            const juniorRoles = [
                "Junior Sales - ALVOIP",
                "Junior Sales - DMS",
                "Junior Sales - AVTECH"
            ];

            const seniorRoles = [
                "Senior Sales - ALVOIP",
                "Senior Sales - DMS",
                "Senior Sales - AVTECH"
            ];

            const hasAnyRole = (roleList) =>
                roleList.some(role => roles.includes(role));


            if (hasAnyRole(juniorRoles) || hasAnyRole(seniorRoles))  {
                frm.dashboard.add_comment(
    				__(`The quotation with a value of ${frm.doc.base_grand_total.toLocaleString()} SR requires Sales Manager approval.`),
    				"yellow"
    			);
           }

        }
    }
});

